package Software
public

  ----------
  -- Data --
  ----------

  data Simple_Type
  properties
    Type_Source_Name => "custom_int";
    Source_Text => ("ping");
    Source_Data_Size => 8 Bytes;
  end Simple_Type;

  -----------------
  -- Subprograms --
  -----------------

  subprogram Do_Ping_Spg
  features
    Data_Source : out parameter Simple_Type;
  properties
    Source_Language => (C);
    Source_Name     => "user_do_ping_spg";
    Source_Text     => ("ping.c");
  end Do_Ping_Spg;

  subprogram Ping_Spg
  features
    Data_Sink : in parameter Simple_Type;
  properties
    Source_Language => (C);
    Source_Name     => "user_ping_spg";
    Source_Text     => ("ping.c");
  end Ping_Spg;

  -------------
  -- Threads --
  -------------

  thread P
  features
    Data_Source : out event data port Simple_Type;
  end P;

  thread implementation P.Impl
  calls
    Mycalls: {
    P_Spg : subprogram Do_Ping_Spg;
    };
  connections
    P1 : parameter P_Spg.Data_Source -> Data_Source;
  properties
    Dispatch_Protocol                  => Periodic;
    Period                             => 2000 Ms;
    Deadline                           => 2000 ms;
    Priority                           => 2;
    Dispatch_Offset                    => 500 Ms;
  end P.Impl;

  thread Q
  features
    Data_Sink : in event data port Simple_Type;
  annex agree {**
    assume "data_sink_input": Data_Sink = 0;
    guarantee "period_constraint": true;
    guarantee "deadline_constraint": true;
    guarantee "priority_constraint": true;
    guarantee "routing_constraint": true;
  **};
  end Q;

  thread implementation Q.Impl
  calls
    Mycalls: {
    Q_Spg : subprogram Ping_Spg;
    };
  connections
    P1 : parameter Data_Sink -> Q_Spg.Data_Sink;
  properties
    Dispatch_Protocol                  => Sporadic;
    Period                             => 10 Ms;
    deadline                           => 10 Ms;
    Priority                           => 1;
  end Q.Impl;

end Software;

